// Compliant: Using heterogeneous comparator
struct HeterogeneousComparator {
    using is_transparent = void;
    bool operator()(const std::string& a, const std::string& b) const {
        return a < b;
    }
    bool operator()(const std::string& a, const char* b) const {
        return a < b;
    }
    bool operator()(const char* a, const std::string& b) const {
        return a < b;
    }
};
std::map<std::string, int, HeterogeneousComparator> m;
m.find("abc"); // No string construction

// Compliant: Using std::less<> for transparent comparison
std::map<std::string, int, std::less<>> m;
m.find("key"); // Direct comparison without string creation
